class Solution:
    def numTimesAllBlue(self, flips) -> int:
        n = len(flips)
        bits = [0] * (n + 1)
        count = 0
        for i, f in enumerate(flips):
            bits[f] = 1
            if all(bits[1:i+2]):
                count += 1
        return count

