var numTimesAllBlue = function(flips) {
    let maxFlip = 0, count = 0;
    for (let step = 1; step <= flips.length; step++) {
        maxFlip = Math.max(maxFlip, flips[step - 1]);
        if (maxFlip === step) count++;
    }
    return count;
};
